using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Preserve the legacy name so existing documents and direct SQL queries still work.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 removed the discriminator prefix from the JSON id property.
            // EF8 format: "Product|123", EF9 default: "123".
            // Preserve the legacy format so existing documents can be read/updated.
            entity.HasDiscriminatorInJsonId();
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

